import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, X, Loader2, ImageIcon, Sparkles, Database, Calendar, Trash
} from 'lucide-react';

// --- SUB-COMPONENTE: MODAL DE GALERÍA (Integrado) ---
const ModalGaleria = ({ onClose, cloudName, API_URL }) => {
  const [subiendo, setSubiendo] = useState(false);
  const [log, setLog] = useState([]);

  const subirAFondo = async (e) => {
    const files = Array.from(e.target.files);
    setSubiendo(true);
    for (const file of files) {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('upload_preset', "PRODUCTOS"); 
      formData.append('folder', "GALERIA_MAESTRA");
      
      try {
        const res = await axios.post(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, formData);
        const nombreLimpio = file.name.split('.')[0].replace(/[-_.]/g, ' ').toLowerCase();
        
        await axios.post(`${API_URL}/api/galeria`, {
          nombreReferencia: nombreLimpio,
          publicId: res.data.public_id,
          url: res.data.secure_url
        });
        setLog(prev => [...prev, { name: file.name, status: 'ok' }]);
      } catch (err) {
        setLog(prev => [...prev, { name: file.name, status: 'error' }]);
      }
    }
    setSubiendo(false);
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '450px'}}>
        <div style={modalHeader}>
          <h3>Biblioteca Maestra</h3>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>
        <input type="file" multiple onChange={subirAFondo} id="up-gal" style={{display:'none'}} />
        <label htmlFor="up-gal" style={dropzoneStyle}>
          {subiendo ? <Loader2 className="animate-spin" /> : <Plus />}
          <span>{subiendo ? 'Subiendo...' : 'Subir fotos nuevas'}</span>
        </label>
        <div style={{maxHeight:'150px', overflowY:'auto', marginTop:'10px'}}>
          {log.map((l, i) => (
            <div key={i} style={{fontSize:'0.8rem', display:'flex', justifyContent:'space-between', padding:'5px 0'}}>
              {l.name} <span>{l.status === 'ok' ? '✅' : '❌'}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const [filas, setFilas] = useState([{ id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [showGaleria, setShowGaleria] = useState(false);
  const [cargando, setCargando] = useState(false);

  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  useEffect(() => {
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data)).catch(e => console.log(e));
  }, [showGaleria]); // Recarga galería al cerrar el modal de subida

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    const nuevasFilas = lineas.map(line => {
      const celdas = line.split('\t');
      const texto = celdas[0] || '';
      return {
        id: Math.random(),
        texto: texto,
        precio: celdas[1] || '',
        stock: celdas[2] || '',
        fotoSugerida: buscarMatch(texto)
      };
    });
    setFilas(nuevasFilas);
  };

  const actualizarFila = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const n = { ...f, [campo]: valor };
        if (campo === 'texto') n.fotoSugerida = buscarMatch(valor);
        return n;
      }
      return f;
    }));
  };

  const publicarOfertas = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas.");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.texto || !f.precio) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.texto,
          precioNuevo: f.precio,
          stock: f.stock || 0,
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId,
          fechaInicio: fechas.inicio,
          fechaFin: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      alert("¡Publicado!");
      setFilas([{ id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }]);
    } catch (e) { alert("Error."); } finally { setCargando(false); }
  };

  return (
    <div style={containerStyle}>
      <div style={headerStyle}>
        <div>
          <h1 style={{margin:0}}>Editor de Inventario</h1>
          <p style={subtitleStyle}>Pega celdas de Excel o escribe directamente.</p>
        </div>
        <button onClick={() => setShowGaleria(true)} style={btnSecondary}>
          <Database size={18}/> Biblioteca de Fotos
        </button>
      </div>

      <div style={tableContainer} onPaste={handlePaste}>
        <table style={excelTable}>
          <thead>
            <tr>
              <th style={thStyle}>Foto</th>
              <th style={thStyle}>Producto</th>
              <th style={thStyle}>Precio $</th>
              <th style={thStyle}>Stock</th>
              <th style={thStyle}></th>
            </tr>
          </thead>
          <tbody>
            {filas.map((f) => (
              <tr key={f.id} style={trStyle}>
                <td style={tdStyle}>
                  {f.fotoSugerida ? 
                    <img alt="Sugerencia" src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_60,h_60,c_fill/v1/${f.fotoSugerida.publicId}`} style={thumbStyle} /> 
                    : <div style={noThumb}><ImageIcon size={20} color="#cbd5e1"/></div>
                  }
                </td>
                <td style={tdStyle}>
                  <input style={inputInvisible} placeholder="Nombre..." value={f.texto} onChange={e => actualizarFila(f.id, 'texto', e.target.value)} />
                </td>
                <td style={tdStyle}>
                  <input style={inputInvisible} type="number" placeholder="0.00" value={f.precio} onChange={e => actualizarFila(f.id, 'precio', e.target.value)} />
                </td>
                <td style={tdStyle}>
                  <input style={inputInvisible} type="number" placeholder="0" value={f.stock} onChange={e => actualizarFila(f.id, 'stock', e.target.value)} />
                </td>
                <td style={tdStyle}>
                  <button onClick={() => setFilas(filas.filter(r => r.id !== f.id))} style={btnDel}><Trash size={14}/></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <button onClick={() => setFilas([...filas, { id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }])} style={btnAddRow}>
          <Plus size={16}/> Añadir fila
        </button>
      </div>

      <div style={footerPanel}>
        <div style={{display:'flex', gap:'15px'}}>
          <input type="date" style={dateInput} value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} />
          <input type="date" style={dateInput} value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} />
        </div>
        <div style={{display:'flex', gap:'10px'}}>
          <button onClick={() => setFilas([{ id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }])} style={btnDanger}>Limpiar</button>
          <button onClick={publicarOfertas} disabled={cargando} style={btnPublish}>
            {cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>} Publicar
          </button>
        </div>
      </div>

      {showGaleria && <ModalGaleria cloudName={CLOUD_NAME} API_URL={API_URL} onClose={() => setShowGaleria(false)} />}
    </div>
  );
};

// --- ESTILOS ---
const containerStyle = { padding: '20px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const subtitleStyle = { color: '#666', fontSize: '0.9rem' };
const tableContainer = { background: 'white', border: '1px solid #ddd', borderRadius: '8px' };
const excelTable = { width: '100%', borderCollapse: 'collapse' };
const thStyle = { textAlign: 'left', padding: '10px', background: '#f5f5f5', fontSize: '0.8rem' };
const tdStyle = { padding: '5px', borderBottom: '1px solid #eee' };
const trStyle = { verticalAlign: 'middle' };
const inputInvisible = { width: '100%', border: 'none', outline: 'none', padding: '10px' };
const thumbStyle = { width: '50px', height: '50px', objectFit: 'cover', borderRadius: '4px' };
const noThumb = { width: '50px', height: '50px', background: '#f9f9f9', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const btnAddRow = { width: '100%', padding: '10px', background: 'none', border: 'none', color: 'blue', cursor: 'pointer' };
const footerPanel = { marginTop: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#f5f5f5', padding: '15px', borderRadius: '8px' };
const dateInput = { padding: '8px', border: '1px solid #ccc', borderRadius: '4px' };
const btnPublish = { background: '#8b5cf6', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '6px', cursor: 'pointer', display: 'flex', gap: '8px' };
const btnDanger = { background: '#fee2e2', color: '#b91c1c', border: 'none', padding: '10px', borderRadius: '6px', cursor: 'pointer' };
const btnSecondary = { padding: '10px', borderRadius: '6px', border: '1px solid #ccc', cursor: 'pointer', display: 'flex', gap: '5px' };
const btnDel = { background: 'none', border: 'none', color: '#ccc', cursor: 'pointer' };
const modalOverlay = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const modalContent = { background: 'white', padding: '20px', borderRadius: '10px' };
const modalHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const closeBtn = { background: 'none', border: 'none', cursor: 'pointer' };
const dropzoneStyle = { border: '2px dashed #ccc', padding: '20px', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', cursor: 'pointer' };

export default GestionOfertas;
